BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name ?ownerName ?ownerType ?qualName WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(STR(?name), "Wavefront%20Calibration%20Lookup%20Table"))
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualName }
  OPTIONAL {
    ?elem vocab:Element_owner ?owner .
    ?owner vocab:NamedElement_name ?ownerName .
    ?owner rdf:type ?ownerType .
  }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childType ?childName WHERE {
  <TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Configuration%2520Tables> vocab:Element_ownedElement ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?ownerElem ?ownerName WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(STR(?name) = "Wavefront%20Calibration%20Lookup%20Table")
  ?elem rdf:type vocab:package .
  ?elem vocab:Element_owner ?ownerElem .
  OPTIONAL { ?ownerElem vocab:NamedElement_name ?ownerName }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?attrName ?attrRdfType ?attrTypeName WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(STR(?ename), "Wavefront%20Calibration%20Lookup%20Table"))
  ?elem rdf:type vocab:block .
  ?elem vocab:StructuredClassifier_ownedAttribute ?attr .
  OPTIONAL { ?attr vocab:NamedElement_name ?attrName }
  OPTIONAL { ?attr rdf:type ?attrRdfType }
  OPTIONAL {
    ?attr vocab:TypedElement_type ?attrType .
    ?attrType vocab:NamedElement_name ?attrTypeName .
  }
}
LIMIT 25
